import { useParams } from "react-router-dom";
import { GetSeason } from "../services/season-service";
import { useEffect, useState } from "react";
import { Season } from "../data/seasons/season";

export default function Fixtures()
{
    const param = useParams();
    const [data, setData] = useState<Season | null>(null);
    useEffect(() => {
        GetSeason(param.id).then(data => setData(data));
    }, []);  
    
    return(
        <div>
            { data ?  <div>{data.startYear} </div> : <p>Loading...</p>}
        </div>
    )

}
